import{_ as n,c as l,o as t,a1 as a}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"Plattformfunktionen: Kernbefehle & Skill-Management | OpenSkills","description":"Lernen Sie die OpenSkills-Plattformfunktionen kennen, meistern Sie Kernoperationen wie Befehle, Installation, Auflisten, Aktualisieren und Entfernen von Skills, und verstehen Sie die Unterschiede zwischen globaler und projektspezifischer Verwaltung.","frontmatter":{"title":"Plattformfunktionen: Kernbefehle & Skill-Management | OpenSkills","sidebarTitle":"Kernoperationen meistern","subtitle":"Plattformfunktionen: Kernbefehle & Skill-Management | OpenSkills","description":"Lernen Sie die OpenSkills-Plattformfunktionen kennen, meistern Sie Kernoperationen wie Befehle, Installation, Auflisten, Aktualisieren und Entfernen von Skills, und verstehen Sie die Unterschiede zwischen globaler und projektspezifischer Verwaltung.","order":2},"headers":[],"relativePath":"de/numman-ali/openskills/platforms/index.md","filePath":"de/numman-ali/openskills/platforms/index.md"}'),i={name:"de/numman-ali/openskills/platforms/index.md"};function s(r,e,d,o,h,u){return t(),l("div",null,[...e[0]||(e[0]=[a('<h1 id="plattformfunktionen" tabindex="-1">Plattformfunktionen <a class="header-anchor" href="#plattformfunktionen" aria-label="Permalink to &quot;Plattformfunktionen&quot;">​</a></h1><p>Dieses Kapitel behandelt die Kernbefehle und das Skill-Management der OpenSkills CLI im Detail und hilft Ihnen, von &quot;Grundlagenkenntnissen&quot; zu &quot;Expertenwissen&quot; zu gelangen.</p><h2 id="voraussetzungen" tabindex="-1">Voraussetzungen <a class="header-anchor" href="#voraussetzungen" aria-label="Permalink to &quot;Voraussetzungen&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Bitte vor dem Start bestätigen</p><p>Bevor Sie mit diesem Kapitel beginnen, stellen Sie sicher, dass Sie das Kapitel <a href="./../start/">Schnellstart</a> abgeschlossen haben, insbesondere:</p><ul><li><a href="./../start/installation/">OpenSkills installieren</a>: OpenSkills CLI wurde erfolgreich installiert</li><li><a href="./../start/first-skill/">Ersten Skill installieren</a>: Grundlegender Installationsprozess für Skills verstanden</li></ul></div><h2 id="inhalt-dieses-kapitels" tabindex="-1">Inhalt dieses Kapitels <a class="header-anchor" href="#inhalt-dieses-kapitels" aria-label="Permalink to &quot;Inhalt dieses Kapitels&quot;">​</a></h2><p>Dieses Kapitel umfasst 6 Themen, die alle Kernfunktionen von OpenSkills abdecken:</p><h3 id="befehlsdetails" tabindex="-1"><a href="./cli-commands/">Befehlsdetails</a> <a class="header-anchor" href="#befehlsdetails" aria-label="Permalink to &quot;[Befehlsdetails](./cli-commands/)&quot;">​</a></h3><p>Vollständige Übersicht über alle 7 Befehle, Parameter und Flags, inklusive Befehlsübersicht. Ideal für Benutzer, die schnell nach Befehlsverwendungen suchen müssen.</p><h3 id="installationsquellen-im-detail" tabindex="-1"><a href="./install-sources/">Installationsquellen im Detail</a> <a class="header-anchor" href="#installationsquellen-im-detail" aria-label="Permalink to &quot;[Installationsquellen im Detail](./install-sources/)&quot;">​</a></h3><p>Detaillierte Erklärung der drei Installationsquellen: GitHub-Repositorys, lokale Pfade und private Git-Repositorys. Anwendungsszenarien, Befehlsformate und Hinweise für jede Methode.</p><h3 id="globale-vs-projektspezifische-installation" tabindex="-1"><a href="./global-vs-project/">Globale vs. projektspezifische Installation</a> <a class="header-anchor" href="#globale-vs-projektspezifische-installation" aria-label="Permalink to &quot;[Globale vs. projektspezifische Installation](./global-vs-project/)&quot;">​</a></h3><p>Erklärung der Unterschiede zwischen <code>--global</code> und der Standard-Installation (projektspezifisch), um Ihnen bei der Wahl des richtigen Installationsorts zu helfen und die Suchprioritätsregeln für Skills zu verstehen.</p><h3 id="installierte-skills-auflisten" tabindex="-1"><a href="./list-skills/">Installierte Skills auflisten</a> <a class="header-anchor" href="#installierte-skills-auflisten" aria-label="Permalink to &quot;[Installierte Skills auflisten](./list-skills/)&quot;">​</a></h3><p>Lernen Sie, den <code>list</code>-Befehl zu verwenden, um installierte Skills anzuzeigen, und verstehen Sie die Bedeutung der Standort-Tags <code>(project)</code> und <code>(global)</code>.</p><h3 id="skills-aktualisieren" tabindex="-1"><a href="./update-skills/">Skills aktualisieren</a> <a class="header-anchor" href="#skills-aktualisieren" aria-label="Permalink to &quot;[Skills aktualisieren](./update-skills/)&quot;">​</a></h3><p>Anleitung zur Verwendung des <code>update</code>-Befehls zum Aktualisieren installierter Skills, mit Unterstützung für vollständige und spezifische Skill-Aktualisierungen, um Skills mit dem Quell-Repository synchron zu halten.</p><h3 id="skills-entfernen" tabindex="-1"><a href="./remove-skills/">Skills entfernen</a> <a class="header-anchor" href="#skills-entfernen" aria-label="Permalink to &quot;[Skills entfernen](./remove-skills/)&quot;">​</a></h3><p>Vorstellung von zwei Löschmethoden: dem interaktiven <code>manage</code>-Befehl und dem skriptbasierten <code>remove</code>-Befehl, um Ihre Skill-Bibliothek effizient zu verwalten.</p><h2 id="lernpfad" tabindex="-1">Lernpfad <a class="header-anchor" href="#lernpfad" aria-label="Permalink to &quot;Lernpfad&quot;">​</a></h2><p>Wählen Sie je nach Ihren Bedürfnissen den passenden Lernpfad:</p><h3 id="pfad-a-systematisches-lernen-empfohlen-fur-einsteiger" tabindex="-1">Pfad A: Systematisches Lernen (empfohlen für Einsteiger) <a class="header-anchor" href="#pfad-a-systematisches-lernen-empfohlen-fur-einsteiger" aria-label="Permalink to &quot;Pfad A: Systematisches Lernen (empfohlen für Einsteiger)&quot;">​</a></h3><p>Lernen Sie alle Inhalte der Reihe nach, um ein vollständiges Wissenssystem aufzubauen:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Befehlsdetails → Installationsquellen → Global vs. Projekt → Skills auflisten → Skills aktualisieren → Skills entfernen</span></span></code></pre></div><h3 id="pfad-b-bedarfsgerechtes-nachschlagen" tabindex="-1">Pfad B: Bedarfsgerechtes Nachschlagen <a class="header-anchor" href="#pfad-b-bedarfsgerechtes-nachschlagen" aria-label="Permalink to &quot;Pfad B: Bedarfsgerechtes Nachschlagen&quot;">​</a></h3><p>Springen Sie direkt zu den relevanten Inhalten basierend auf Ihrer aktuellen Aufgabe:</p><table tabindex="0"><thead><tr><th>Was möchten Sie tun?</th><th>Lesen Sie diesen Artikel</th></tr></thead><tbody><tr><td>Die Verwendung eines bestimmten Befehls nachschlagen</td><td><a href="./cli-commands/">Befehlsdetails</a></td></tr><tr><td>Einen Skill aus einem privaten Repository installieren</td><td><a href="./install-sources/">Installationsquellen im Detail</a></td></tr><tr><td>Entscheiden, ob global oder projektspezifisch installiert werden soll</td><td><a href="./global-vs-project/">Global vs. Projekt</a></td></tr><tr><td>Anzeigen, welche Skills bereits installiert sind</td><td><a href="./list-skills/">Installierte Skills auflisten</a></td></tr><tr><td>Skills auf die neueste Version aktualisieren</td><td><a href="./update-skills/">Skills aktualisieren</a></td></tr><tr><td>Nicht mehr benötigte Skills bereinigen</td><td><a href="./remove-skills/">Skills entfernen</a></td></tr></tbody></table><h2 id="nachste-schritte" tabindex="-1">Nächste Schritte <a class="header-anchor" href="#nachste-schritte" aria-label="Permalink to &quot;Nächste Schritte&quot;">​</a></h2><p>Nach Abschluss dieses Kapitels haben Sie die täglichen Verwendungsfähigkeiten von OpenSkills gemeistert. Als Nächstes können Sie:</p><ul><li><strong><a href="./../advanced/">Erweiterte Funktionen</a></strong>: Lernen Sie erweiterte Funktionen wie den Universal-Modus, benutzerdefinierte Ausgabepfade, symbolische Links und die Erstellung benutzerdefinierter Skills kennen</li><li><strong><a href="./../faq/">FAQ</a></strong>: Konsultieren Sie FAQ und Fehlerbehebungsanleitungen bei Problemen</li></ul>',29)])])}const p=n(i,[["render",s]]);export{c as __pageData,p as default};
